// Formato Sage Despachos (enlace contable): tabulador, sin cabecera, indicador D/H + importe.
// Columnas: Ejercicio, Fecha(dd/mm/aaaa), Asiento, Cuenta, Concepto, D|H, Importe, Documento, NIF.
// Fuente: asientos+apuntes reales de Kontia. Validar con una importación de prueba antes de uso masivo.
const rows = $('Leer Apuntes PostgreSQL').all().map(i => i.json);
const body = $('Webhook').first().json.body || {};
const ejercicio = String(body.ejercicio || new Date().getFullYear());
const fmtCo = (n) => ((Number(n) || 0).toFixed(2)).replace('.', ',');
const fEs = (iso) => { const s = String(iso || '').substring(0, 10); const p = s.split('-'); return p.length === 3 ? `${p[2]}/${p[1]}/${p[0]}` : s; };
const clean = (s, len) => String(s || '').replace(/[\t\r\n]/g, ' ').substring(0, len);

const lineas = [];
for (const r of rows) {
  const debe = Number(r.debe) || 0;
  const esDebe = debe > 0;
  lineas.push([
    ejercicio, fEs(r.fecha), r.asiento, r.cuenta,
    clean(r.concepto, 50),
    esDebe ? 'D' : 'H',
    fmtCo(esDebe ? r.debe : r.haber),
    clean(r.documento, 20), clean(r.nif, 15)
  ].join('\t'));
}

return [{
  json: {
    success: true,
    total_apuntes: rows.length,
    formato: 'Sage Despachos',
    csv_content: lineas.join('\r\n'),
    filename: 'kontia_sagedespachos_' + ejercicio + '.txt'
  }
}];
